from __future__ import annotations

from collections.abc import Callable, Iterator
from pathlib import Path
from typing import TYPE_CHECKING

from voxlocal._audio import AudioChunk, AudioResult
from voxlocal._config import (
    SUPPORTED_LANGUAGES,
    SUPPORTED_STT_LANGUAGES,
    SUPPORTED_TTS_LANGUAGES,
    EngineConfig,
    get_stt_config,
    get_tts_config,
)
from voxlocal._download import DownloadManager, DownloadProgress
from voxlocal._errors import (
    DependencyMissingError,
    EngineNotSupportedError,
    LanguageNotSupportedError,
    ModelDownloadError,
    ModelNotDownloadedError,
    SynthesisError,
    TranscriptionError,
    VoxLocalError,
)
from voxlocal._stream import DEFAULT_PREFETCH, assemble_stream
from voxlocal._version import __version__

if TYPE_CHECKING:
    from voxlocal.playback import PlaybackEvent


class VoxLocal:
    """Local STT/TTS facade with explicit setup and portable streaming."""

    def __init__(
        self,
        language: str,
        stt_engine: str | None = None,
        tts_engine: str | None = None,
        *,
        cache_dir: str | Path | None = None,
    ):
        if language not in SUPPORTED_LANGUAGES:
            raise LanguageNotSupportedError(language)

        self.language = language
        self._stt_config = self._optional_config(
            get_stt_config, language, stt_engine
        )
        self._tts_config = self._optional_config(
            get_tts_config, language, tts_engine
        )
        self._download_manager = DownloadManager(cache_dir)
        self._stt = None
        self._tts = None

    @staticmethod
    def _optional_config(
        resolver: Callable[[str, str | None], EngineConfig],
        language: str,
        engine: str | None,
    ) -> EngineConfig | None:
        try:
            return resolver(language, engine)
        except LanguageNotSupportedError:
            if engine is not None:
                raise
            return None

    def setup(
        self,
        *,
        stt: bool = True,
        tts: bool = True,
        warmup_tts: bool = True,
    ) -> list[DownloadProgress]:
        """Eagerly download selected models and optionally warm TTS."""
        return list(
            self.setup_iter(stt=stt, tts=tts, warmup_tts=warmup_tts)
        )

    def setup_iter(
        self,
        *,
        stt: bool = True,
        tts: bool = True,
        warmup_tts: bool = True,
    ) -> Iterator[DownloadProgress]:
        """Yield model setup progress while performing setup."""
        selected: list[EngineConfig] = []
        if stt and self._stt_config is not None:
            selected.append(self._stt_config)
        if tts and self._tts_config is not None:
            selected.append(self._tts_config)

        seen: set[str] = set()
        for config in selected:
            if config.model_id in seen:
                continue
            seen.add(config.model_id)
            yield from self._download_manager.download(config.model_id)

        if tts and warmup_tts and self._tts_config is not None:
            self._ensure_tts()
            self._tts.warmup()

    def download_model(self, model_id: str) -> list[DownloadProgress]:
        """Eagerly download one model and return its progress records."""
        return list(self.download_model_iter(model_id))

    def download_model_iter(
        self, model_id: str
    ) -> Iterator[DownloadProgress]:
        """Yield progress while downloading one model."""
        yield from self._download_manager.download(model_id)

    def _require_capability(
        self, config: EngineConfig | None, capability: str
    ) -> EngineConfig:
        if config is None:
            raise LanguageNotSupportedError(self.language, capability)
        return config

    def _ensure_stt(self) -> None:
        if self._stt is not None:
            return
        config = self._require_capability(self._stt_config, "stt")
        model_dir = self._download_manager.require_downloaded(config.model_id)
        from voxlocal.stt import resolve_stt_engine

        self._stt = resolve_stt_engine(
            config.engine, self.language, model_dir
        )

    def _ensure_tts(self) -> None:
        if self._tts is not None:
            return
        config = self._require_capability(self._tts_config, "tts")
        model_dir = self._download_manager.require_downloaded(config.model_id)
        from voxlocal.tts import resolve_tts_engine

        self._tts = resolve_tts_engine(
            config.engine, self.language, model_dir
        )

    def transcribe(self, audio_path: str | Path) -> str:
        """Transcribe one audio file."""
        self._ensure_stt()
        try:
            return self._stt.transcribe(str(audio_path))
        except VoxLocalError:
            raise
        except Exception as error:
            raise TranscriptionError(str(error)) from error

    def speak(self, text: str) -> AudioResult:
        """Synthesize one complete higher-quality result."""
        self._ensure_tts()
        try:
            return self._tts.speak(text)
        except VoxLocalError:
            raise
        except Exception as error:
            raise SynthesisError(str(error)) from error

    def speak_iter(
        self, text: str, chunk_by: str = "progressive"
    ) -> Iterator[AudioResult]:
        """Yield raw engine results as each text chunk is generated."""
        self._ensure_tts()
        try:
            yield from self._tts.speak_iter(text, chunk_by)
        except VoxLocalError:
            raise
        except Exception as error:
            raise SynthesisError(str(error)) from error

    def stream(
        self,
        text: str,
        *,
        chunk_by: str = "progressive",
        prefetch: int = DEFAULT_PREFETCH,
    ) -> Iterator[AudioChunk]:
        """Yield portable, trimmed and crossfaded PCM-ready blocks."""
        return assemble_stream(
            self.speak_iter(text, chunk_by=chunk_by),
            prefetch=prefetch,
        )

    def play(
        self,
        text: str,
        *,
        on_event: Callable[[PlaybackEvent], None] | None = None,
        device: int | str | None = None,
        prefetch: int = DEFAULT_PREFETCH,
    ) -> None:
        """Convenience wrapper around the optional playback adapter."""
        from voxlocal.playback import play

        play(
            self.stream(text, prefetch=prefetch),
            on_event=on_event,
            device=device,
        )


__all__ = [
    "__version__",
    "AudioChunk",
    "AudioResult",
    "DependencyMissingError",
    "DownloadProgress",
    "EngineNotSupportedError",
    "LanguageNotSupportedError",
    "ModelDownloadError",
    "ModelNotDownloadedError",
    "SUPPORTED_LANGUAGES",
    "SUPPORTED_STT_LANGUAGES",
    "SUPPORTED_TTS_LANGUAGES",
    "SynthesisError",
    "TranscriptionError",
    "VoxLocal",
    "VoxLocalError",
]

from __future__ import annotations

from dataclasses import dataclass

from voxlocal._errors import EngineNotSupportedError, LanguageNotSupportedError


@dataclass(frozen=True)
class EngineConfig:
    """Resolved engine and model selection for one capability."""

    engine: str
    model_id: str
    size_mb: int

    def __getitem__(self, key: str) -> str | int:
        """Preserve the original mapping-style private API."""
        return getattr(self, key)


MODEL_REGISTRY: dict[str, dict[str, EngineConfig]] = {
    "stt": {
        "es": EngineConfig("moonshine", "moonshine_es", 60),
        "en": EngineConfig("sensevoice", "sensevoice_onnx", 230),
        "ja": EngineConfig("sensevoice", "sensevoice_onnx", 230),
        "ko": EngineConfig("sensevoice", "sensevoice_onnx", 230),
        "fr": EngineConfig("whisper", "whisper_base", 139),
        "de": EngineConfig("whisper", "whisper_base", 139),
        "pt": EngineConfig("whisper", "whisper_base", 139),
        "auto": EngineConfig("whisper", "whisper_base", 139),
    },
    "tts": {
        "es": EngineConfig("supertonic", "supertonic_3", 99),
        "en": EngineConfig("supertonic", "supertonic_3", 99),
        "ja": EngineConfig("supertonic", "supertonic_3", 99),
        "ko": EngineConfig("supertonic", "supertonic_3", 99),
        "fr": EngineConfig("supertonic", "supertonic_3", 99),
        "de": EngineConfig("supertonic", "supertonic_3", 99),
        "pt": EngineConfig("supertonic", "supertonic_3", 99),
    },
}

ENGINE_MODELS: dict[str, dict[str, dict[str, EngineConfig]]] = {
    "stt": {
        "whisper": {
            language: EngineConfig("whisper", "whisper_base", 139)
            for language in MODEL_REGISTRY["stt"]
        },
        "moonshine": {
            "es": EngineConfig("moonshine", "moonshine_es", 60),
        },
        "sensevoice": {
            language: EngineConfig("sensevoice", "sensevoice_onnx", 230)
            for language in ("en", "ja", "ko")
        },
    },
    "tts": {
        "supertonic": {
            language: EngineConfig("supertonic", "supertonic_3", 99)
            for language in MODEL_REGISTRY["tts"]
        }
    },
}

SUPPORTED_STT_LANGUAGES = tuple(sorted(MODEL_REGISTRY["stt"]))
SUPPORTED_TTS_LANGUAGES = tuple(sorted(MODEL_REGISTRY["tts"]))
SUPPORTED_LANGUAGES = sorted(
    set(MODEL_REGISTRY["stt"].keys()) | set(MODEL_REGISTRY["tts"].keys())
)


def _get_config(
    capability: str, language: str, engine: str | None
) -> EngineConfig:
    if engine is None:
        try:
            return MODEL_REGISTRY[capability][language]
        except KeyError as error:
            raise LanguageNotSupportedError(language, capability) from error

    try:
        language_models = ENGINE_MODELS[capability][engine]
    except KeyError as error:
        raise EngineNotSupportedError(capability, engine, language) from error
    try:
        return language_models[language]
    except KeyError as error:
        raise EngineNotSupportedError(capability, engine, language) from error


def get_stt_config(language: str, engine: str | None = None) -> EngineConfig:
    """Resolve STT configuration, including explicit engine overrides."""
    return _get_config("stt", language, engine)


def get_tts_config(language: str, engine: str | None = None) -> EngineConfig:
    """Resolve TTS configuration, including explicit engine overrides."""
    return _get_config("tts", language, engine)

from __future__ import annotations

from collections.abc import Iterator
from dataclasses import dataclass
from pathlib import Path

from platformdirs import user_cache_dir

from voxlocal._errors import (
    DependencyMissingError,
    ModelDownloadError,
    ModelNotDownloadedError,
)

SENSEVOICE_REPO = "lovemefan/SenseVoice-onnx"
SENSEVOICE_REVISION = "8a5ee5b014950890a07246bc590a4f77b3ef67a4"
SENSEVOICE_FILES = (
    "sense-voice-encoder-int8.onnx",
    "embedding.npy",
    "chn_jpn_yue_eng_ko_spectok.bpe.model",
    "am.mvn",
)
SUPERTONIC_FILES = (
    "onnx/tts.json",
    "onnx/unicode_indexer.json",
    "onnx/duration_predictor.onnx",
    "onnx/text_encoder.onnx",
    "onnx/vector_estimator.onnx",
    "onnx/vocoder.onnx",
    "voice_styles/M1.json",
)
MOONSHINE_ES_FILES = (
    "download.moonshine.ai/model/base-es/quantized/base-es/encoder_model.ort",
    "download.moonshine.ai/model/base-es/quantized/base-es/decoder_model_merged.ort",
    "download.moonshine.ai/model/base-es/quantized/base-es/tokenizer.bin",
)


@dataclass(frozen=True)
class DownloadProgress:
    """Observable model setup state."""

    model_id: str
    percent: int
    downloaded: str
    total: str
    description: str


class DownloadManager:
    """Own all model paths, availability checks, and explicit downloads."""

    def __init__(self, cache_dir: str | Path | None = None):
        root = cache_dir or user_cache_dir("voxlocal")
        self.cache_dir = Path(root).expanduser()
        self.cache_dir.mkdir(parents=True, exist_ok=True)

    def is_downloaded(self, model_id: str) -> bool:
        """Return true only when required model files exist on disk."""
        if model_id == "supertonic_3":
            return self._all_exist(self.model_dir(model_id), SUPERTONIC_FILES)
        if model_id == "whisper_base":
            return (self.model_dir(model_id) / "base.pt").is_file()
        if model_id == "sensevoice_onnx":
            return self._all_exist(self.model_dir(model_id), SENSEVOICE_FILES)
        if model_id == "moonshine_es":
            return self._all_exist(self.model_dir(model_id), MOONSHINE_ES_FILES)
        raise ValueError(f"Unknown model: {model_id}")

    def require_downloaded(self, model_id: str) -> Path:
        """Return the model directory or raise the public setup error."""
        if not self.is_downloaded(model_id):
            raise ModelNotDownloadedError(model_id)
        return self.model_dir(model_id)

    def download(self, model_id: str) -> Iterator[DownloadProgress]:
        """Download one known model with explicit start and completion records."""
        if self.is_downloaded(model_id):
            yield self._progress(model_id, 100, "already cached")
            return

        yield self._progress(model_id, 0, "download started")
        try:
            if model_id == "supertonic_3":
                self._download_supertonic()
            elif model_id == "whisper_base":
                self._download_whisper()
            elif model_id == "sensevoice_onnx":
                self._download_sensevoice()
            elif model_id == "moonshine_es":
                self._download_moonshine()
            else:
                raise ValueError(f"Unknown model: {model_id}")
        except (DependencyMissingError, ValueError):
            raise
        except Exception as error:
            raise ModelDownloadError(
                f"Failed to download model '{model_id}': {error}"
            ) from error

        if not self.is_downloaded(model_id):
            raise ModelDownloadError(
                f"Download for '{model_id}' completed without all required files"
            )
        yield self._progress(model_id, 100, "download complete")

    def model_dir(self, model_id: str) -> Path:
        """Return the engine-specific directory for a model."""
        directories = {
            "supertonic_3": self.cache_dir / "supertonic-3",
            "whisper_base": self.cache_dir / "whisper",
            "sensevoice_onnx": self.cache_dir / "sensevoice-onnx",
            "moonshine_es": self.cache_dir / "moonshine",
        }
        try:
            return directories[model_id]
        except KeyError as error:
            raise ValueError(f"Unknown model: {model_id}") from error

    def get_model_path(self, model_id: str) -> Path:
        """Backward-compatible alias for model_dir()."""
        return self.model_dir(model_id)

    @staticmethod
    def _all_exist(root: Path, relative_paths: tuple[str, ...]) -> bool:
        return all((root / relative_path).is_file() for relative_path in relative_paths)

    @staticmethod
    def _progress(
        model_id: str, percent: int, description: str
    ) -> DownloadProgress:
        return DownloadProgress(
            model_id=model_id,
            percent=percent,
            downloaded="complete" if percent == 100 else "pending",
            total="unknown",
            description=f"{model_id}: {description}",
        )

    def _download_supertonic(self) -> None:
        try:
            from supertonic.loader import download_model
        except ImportError as error:
            raise DependencyMissingError("supertonic", "tts") from error

        model_dir = self.model_dir("supertonic_3")
        model_dir.parent.mkdir(parents=True, exist_ok=True)
        download_model(model_dir, model_name="supertonic-3")

    def _download_whisper(self) -> None:
        try:
            import whisper
        except ImportError as error:
            raise DependencyMissingError("openai-whisper", "whisper") from error

        model = whisper.load_model(
            "base", download_root=str(self.model_dir("whisper_base"))
        )
        del model

    def _download_sensevoice(self) -> None:
        try:
            from huggingface_hub import snapshot_download
        except ImportError as error:
            raise DependencyMissingError("huggingface-hub", "sensevoice") from error

        snapshot_download(
            repo_id=SENSEVOICE_REPO,
            revision=SENSEVOICE_REVISION,
            local_dir=str(self.model_dir("sensevoice_onnx")),
            allow_patterns=list(SENSEVOICE_FILES),
        )

    def _download_moonshine(self) -> None:
        try:
            from moonshine_voice import get_model_for_language
        except ImportError as error:
            raise DependencyMissingError("moonshine-voice", "moonshine") from error

        get_model_for_language(
            "es", cache_root=self.model_dir("moonshine_es")
        )

from __future__ import annotations

from collections.abc import Iterable, Iterator
from dataclasses import dataclass
from queue import Full, Queue
from threading import Event, Thread

import numpy as np

from voxlocal._audio import AudioChunk, AudioResult
from voxlocal._errors import SynthesisError

CROSSFADE_SECONDS = 0.08
BOUNDARY_PADDING_SECONDS = 0.06
SILENCE_THRESHOLD = 0.002
DEFAULT_PREFETCH = 2


def trim_boundary_silence(
    audio: np.ndarray,
    sample_rate: int,
    *,
    trim_start: bool,
    trim_end: bool,
) -> np.ndarray:
    """Remove generated edge silence while retaining a natural short pause."""
    normalized = np.asarray(audio, dtype=np.float32)
    active = np.flatnonzero(np.abs(normalized) > SILENCE_THRESHOLD)
    if len(active) == 0:
        return normalized

    padding = int(BOUNDARY_PADDING_SECONDS * sample_rate)
    start = max(0, int(active[0]) - padding) if trim_start else 0
    end = (
        min(len(normalized), int(active[-1]) + padding + 1)
        if trim_end
        else len(normalized)
    )
    return normalized[start:end]


@dataclass
class StreamAssembler:
    """Convert raw synthesis results into non-repeating gapless blocks."""

    sample_rate: int
    overlap: int
    _tail: np.ndarray | None = None
    _sequence: int = 0

    def push(self, source_index: int, audio: np.ndarray) -> AudioChunk | None:
        """Add one source chunk and return its immediately playable block."""
        current = trim_boundary_silence(
            audio,
            self.sample_rate,
            trim_start=source_index > 0,
            trim_end=True,
        )
        if len(current) == 0:
            return None

        if self._tail is None:
            body, self._tail = self._split_tail(current)
        else:
            body, self._tail = self._join_boundary(self._tail, current)

        if len(body) == 0:
            return None
        chunk = AudioChunk(
            sequence=self._sequence,
            numpy=body,
            sample_rate=self.sample_rate,
            source_chunk=source_index,
        )
        self._sequence += 1
        return chunk

    def finish(self) -> AudioChunk | None:
        """Flush the one retained tail exactly once."""
        if self._tail is None or len(self._tail) == 0:
            return None
        chunk = AudioChunk(
            sequence=self._sequence,
            numpy=self._tail,
            sample_rate=self.sample_rate,
            final=True,
        )
        self._tail = None
        self._sequence += 1
        return chunk

    def _split_tail(self, current: np.ndarray) -> tuple[np.ndarray, np.ndarray]:
        if self.overlap <= 0 or len(current) <= self.overlap:
            return np.empty(0, dtype=np.float32), current
        return current[:-self.overlap], current[-self.overlap :]

    def _join_boundary(
        self, previous_tail: np.ndarray, current: np.ndarray
    ) -> tuple[np.ndarray, np.ndarray]:
        overlap = min(self.overlap, len(previous_tail), len(current))
        if overlap <= 0:
            combined = np.concatenate([previous_tail, current])
            return self._split_tail(combined)

        fade_out = np.linspace(1.0, 0.0, overlap, dtype=np.float32)
        fade_in = np.linspace(0.0, 1.0, overlap, dtype=np.float32)
        boundary = (
            previous_tail[-overlap:] * fade_out + current[:overlap] * fade_in
        )
        prefix = previous_tail[:-overlap]
        remainder = current[overlap:]
        combined = np.concatenate([prefix, boundary, remainder])
        return self._split_tail(combined)


def prefetch_results(
    results: Iterable[AudioResult], *, maxsize: int = DEFAULT_PREFETCH
) -> Iterator[AudioResult]:
    """Yield chunk zero promptly, then prefetch later chunks on one worker."""
    if maxsize < 1:
        raise ValueError("prefetch must be at least 1")

    iterator = iter(results)
    try:
        first = next(iterator)
    except StopIteration:
        return

    queue: Queue[AudioResult | Exception | None] = Queue(maxsize=maxsize)
    cancelled = Event()

    def put(item: AudioResult | Exception | None) -> bool:
        while not cancelled.is_set():
            try:
                queue.put(item, timeout=0.1)
                return True
            except Full:
                continue
        return False

    def produce() -> None:
        try:
            for result in iterator:
                if cancelled.is_set() or not put(result):
                    return
        except Exception as error:
            put(error)
        finally:
            put(None)

    producer = Thread(target=produce, name="voxlocal-stream-producer", daemon=True)
    producer.start()
    try:
        yield first
        while True:
            item = queue.get()
            if item is None:
                break
            if isinstance(item, Exception):
                raise SynthesisError(str(item)) from item
            yield item
    finally:
        cancelled.set()
        producer.join(timeout=1.0)


def assemble_stream(
    results: Iterable[AudioResult], *, prefetch: int = DEFAULT_PREFETCH
) -> Iterator[AudioChunk]:
    """Prefetch raw synthesis and emit trimmed, crossfaded portable chunks."""
    assembler: StreamAssembler | None = None
    for source_index, result in enumerate(
        prefetch_results(results, maxsize=prefetch)
    ):
        if assembler is None:
            assembler = StreamAssembler(
                sample_rate=result.sample_rate,
                overlap=int(CROSSFADE_SECONDS * result.sample_rate),
            )
        elif result.sample_rate != assembler.sample_rate:
            raise SynthesisError(
                f"Sample rate changed from {assembler.sample_rate} "
                f"to {result.sample_rate}"
            )

        chunk = assembler.push(source_index, result.numpy)
        if chunk is not None:
            yield chunk

    if assembler is None:
        raise SynthesisError("TTS produced no audio chunks")
    final = assembler.finish()
    if final is not None:
        yield final

from __future__ import annotations

import base64
import io
from dataclasses import dataclass
from pathlib import Path
from typing import Any

import numpy as np
import soundfile as sf


def _mono_float32(audio: np.ndarray) -> np.ndarray:
    """Normalize generated audio to a contiguous mono float32 array."""
    normalized = np.asarray(audio, dtype=np.float32)
    if normalized.ndim == 2 and 1 in normalized.shape:
        normalized = normalized.reshape(-1)
    if normalized.ndim != 1:
        raise ValueError("Audio must be a mono one-dimensional array")
    return np.ascontiguousarray(normalized)


def _pcm_s16le(audio: np.ndarray) -> bytes:
    """Encode normalized floating-point audio as portable signed PCM16."""
    clipped = np.clip(audio, -1.0, 1.0)
    return (clipped * 32767.0).astype("<i2").tobytes()


@dataclass(frozen=True)
class AudioResult:
    """Result of TTS synthesis."""

    numpy: np.ndarray
    sample_rate: int

    def __post_init__(self) -> None:
        if self.sample_rate <= 0:
            raise ValueError("sample_rate must be positive")
        object.__setattr__(self, "numpy", _mono_float32(self.numpy))

    @property
    def duration_seconds(self) -> float:
        """Audio duration in seconds."""
        return len(self.numpy) / self.sample_rate

    @property
    def bytes(self) -> bytes:
        """Convert to WAV bytes."""
        buf = io.BytesIO()
        sf.write(buf, self.numpy, self.sample_rate, format="WAV")
        return buf.getvalue()

    @property
    def pcm_s16le(self) -> bytes:
        """Raw mono signed 16-bit little-endian PCM."""
        return _pcm_s16le(self.numpy)

    def save(self, path: str | Path) -> None:
        """Save as WAV file."""
        sf.write(path, self.numpy, self.sample_rate)


@dataclass(frozen=True)
class AudioChunk:
    """Portable streaming audio block independent of playback libraries."""

    sequence: int
    numpy: np.ndarray
    sample_rate: int
    final: bool = False
    source_chunk: int | None = None

    def __post_init__(self) -> None:
        if self.sequence < 0:
            raise ValueError("sequence must be non-negative")
        if self.sample_rate <= 0:
            raise ValueError("sample_rate must be positive")
        object.__setattr__(self, "numpy", _mono_float32(self.numpy))

    @property
    def duration_seconds(self) -> float:
        """Audio duration in seconds."""
        return len(self.numpy) / self.sample_rate

    @property
    def pcm_s16le(self) -> bytes:
        """Raw mono signed 16-bit little-endian PCM."""
        return _pcm_s16le(self.numpy)

    def to_wire_dict(self) -> dict[str, Any]:
        """Serialize metadata and PCM for NDJSON or message transports."""
        return {
            "type": "audio_chunk",
            "sequence": self.sequence,
            "sample_rate": self.sample_rate,
            "channels": 1,
            "encoding": "pcm_s16le",
            "final": self.final,
            "source_chunk": self.source_chunk,
            "audio_base64": base64.b64encode(self.pcm_s16le).decode("ascii"),
        }

class VoxLocalError(Exception):
    """Base exception for VoxLocal."""


class LanguageNotSupportedError(VoxLocalError):
    def __init__(self, language: str, capability: str | None = None):
        self.language = language
        self.capability = capability
        detail = f" for {capability}" if capability else ""
        super().__init__(f"Language not supported{detail}: {language}")


class EngineNotSupportedError(VoxLocalError):
    """Raised when an engine cannot serve the requested language."""

    def __init__(self, capability: str, engine: str, language: str):
        self.capability = capability
        self.engine = engine
        self.language = language
        super().__init__(
            f"{capability.upper()} engine '{engine}' does not support language "
            f"'{language}'"
        )


class ModelNotDownloadedError(VoxLocalError):
    def __init__(self, model_id: str, message: str | None = None):
        self.model_id = model_id
        self.message = (
            message
            or "Model not downloaded. Run v.setup() or "
            f"v.download_model('{model_id}') first."
        )
        super().__init__(self.message)


class ModelDownloadError(VoxLocalError):
    """Raised when model setup fails."""


class DependencyMissingError(VoxLocalError):
    """Raised when an optional feature dependency is unavailable."""

    def __init__(self, dependency: str, extra: str):
        self.dependency = dependency
        self.extra = extra
        super().__init__(
            f"Missing optional dependency '{dependency}'. "
            f"Install it with: pip install 'voxlocal[{extra}]'"
        )


class TranscriptionError(VoxLocalError):
    """Error during transcription."""


class SynthesisError(VoxLocalError):
    """Error during synthesis."""

from __future__ import annotations

import argparse
import json
from collections.abc import Callable, Iterator
from pathlib import Path
from tempfile import NamedTemporaryFile
from threading import Lock
from typing import Any

from voxlocal import AudioChunk, VoxLocal
from voxlocal._errors import DependencyMissingError, VoxLocalError


def chunk_to_ndjson(chunk: AudioChunk) -> bytes:
    """Encode one portable chunk as a newline-delimited JSON record."""
    return (
        json.dumps(chunk.to_wire_dict(), separators=(",", ":")) + "\n"
    ).encode("utf-8")


def create_app(
    *,
    voxlocal_factory: Callable[..., VoxLocal] = VoxLocal,
    cache_dir: str | Path | None = None,
    cors_origins: tuple[str, ...] = (),
) -> Any:
    """Create the optional FastAPI transport without importing it at package load."""
    try:
        from fastapi import Body, FastAPI, HTTPException
        from fastapi.responses import Response, StreamingResponse
    except ImportError as error:
        raise DependencyMissingError("fastapi", "server") from error

    app = FastAPI(title="VoxLocal", version="1.0")
    if cors_origins:
        from fastapi.middleware.cors import CORSMiddleware

        app.add_middleware(
            CORSMiddleware,
            allow_origins=list(cors_origins),
            allow_methods=["GET", "POST"],
            allow_headers=["content-type"],
        )
    instances: dict[tuple[str, str], VoxLocal] = {}
    instances_lock = Lock()

    def get_instance(language: str, capability: str) -> VoxLocal:
        key = (language, capability)
        with instances_lock:
            instance = instances.get(key)
            if instance is None:
                kwargs: dict[str, Any] = {"language": language}
                if cache_dir is not None:
                    kwargs["cache_dir"] = cache_dir
                instance = voxlocal_factory(**kwargs)
                instance.setup(
                    stt=capability == "stt",
                    tts=capability == "tts",
                    warmup_tts=capability == "tts",
                )
                instances[key] = instance
            return instance

    @app.get("/v1/health")
    def health() -> dict[str, str]:
        return {"status": "ok"}

    def parse_request(request: dict[str, str]) -> tuple[str, str]:
        text = request.get("text", "").strip()
        language = request.get("language", "").strip()
        if not text or not language:
            raise HTTPException(
                status_code=422,
                detail="'text' and 'language' must be non-empty strings",
            )
        return text, language

    @app.post("/v1/tts")
    def synthesize(request: dict[str, str]) -> Response:
        text, language = parse_request(request)
        try:
            audio = get_instance(language, "tts").speak(text)
        except VoxLocalError as error:
            raise HTTPException(status_code=400, detail=str(error)) from error
        return Response(content=audio.bytes, media_type="audio/wav")

    @app.post("/v1/tts/stream")
    def stream(request: dict[str, str]) -> StreamingResponse:
        text, language = parse_request(request)
        try:
            instance = get_instance(language, "tts")
        except VoxLocalError as error:
            raise HTTPException(status_code=400, detail=str(error)) from error

        def records() -> Iterator[bytes]:
            chunks = instance.stream(text)
            try:
                for chunk in chunks:
                    yield chunk_to_ndjson(chunk)
            except VoxLocalError as error:
                yield (
                    json.dumps(
                        {"type": "error", "error": str(error)},
                        separators=(",", ":"),
                    )
                    + "\n"
                ).encode("utf-8")
            finally:
                chunks.close()

        return StreamingResponse(
            records(), media_type="application/x-ndjson"
        )

    @app.post("/v1/stt")
    def transcribe(
        language: str,
        audio: bytes = Body(media_type="audio/wav"),
    ) -> dict[str, str]:
        if not audio:
            raise HTTPException(status_code=422, detail="WAV body must not be empty")
        temporary_path: Path | None = None
        try:
            with NamedTemporaryFile(suffix=".wav", delete=False) as temporary:
                temporary.write(audio)
                temporary_path = Path(temporary.name)
            text = get_instance(language, "stt").transcribe(temporary_path)
        except VoxLocalError as error:
            raise HTTPException(status_code=400, detail=str(error)) from error
        finally:
            if temporary_path is not None:
                temporary_path.unlink(missing_ok=True)
        return {"text": text}

    return app


def main() -> None:
    """Run the optional HTTP transport."""
    parser = argparse.ArgumentParser(description="Run the VoxLocal HTTP API")
    parser.add_argument("--host", default="127.0.0.1")
    parser.add_argument("--port", type=int, default=8765)
    parser.add_argument("--cache-dir")
    parser.add_argument(
        "--cors-origin",
        action="append",
        default=[],
        help="Allowed browser origin; repeat for multiple origins",
    )
    args = parser.parse_args()
    try:
        import uvicorn
    except ImportError as error:
        raise DependencyMissingError("uvicorn", "server") from error

    uvicorn.run(
        create_app(
            cache_dir=args.cache_dir,
            cors_origins=tuple(args.cors_origin),
        ),
        host=args.host,
        port=args.port,
    )


if __name__ == "__main__":
    main()

