def parse_request(request: dict[str, str]) -> tuple[str, str]:
    text = request.get("text", "").strip()
    language = request.get("language", "").strip()
    if not text or not language:
        raise HTTPException(
            status_code=422,
            detail="'text' and 'language' must be non-empty strings",
        )
    return text, language

@app.post("/v1/tts")
def synthesize(request: dict[str, str]) -> Response:
    text, language = parse_request(request)
    try:
        audio = get_instance(language, "tts").speak(text)
    except VoxLocalError as error:
        raise HTTPException(status_code=400, detail=str(error)) from error
    return Response(content=audio.bytes, media_type="audio/wav")

@app.post("/v1/tts/stream")
def stream(request: dict[str, str]) -> StreamingResponse:
    text, language = parse_request(request)
    try:
        instance = get_instance(language, "tts")
    except VoxLocalError as error:
        raise HTTPException(status_code=400, detail=str(error)) from error

    def records() -> Iterator[bytes]:
        chunks = instance.stream(text)
        try:
            for chunk in chunks:
                yield chunk_to_ndjson(chunk)
        except VoxLocalError as error:
            yield (
                json.dumps(
                    {"type": "error", "error": str(error)},
                    separators=(",", ":"),
                )
                + "\n"
            ).encode("utf-8")
        finally:
            chunks.close()

    return StreamingResponse(
        records(), media_type="application/x-ndjson"
    )

@app.post("/v1/stt")
def transcribe(
    language: str,
    audio: bytes = Body(media_type="audio/wav"),
) -> dict[str, str]:
    if not audio:
        raise HTTPException(status_code=422, detail="WAV body must not be empty")
    temporary_path: Path | None = None
    try:
        with NamedTemporaryFile(suffix=".wav", delete=False) as temporary:
            temporary.write(audio)
            temporary_path = Path(temporary.name)
        text = get_instance(language, "stt").transcribe(temporary_path)
    except VoxLocalError as error:
        raise HTTPException(status_code=400, detail=str(error)) from error
    finally:
        if temporary_path is not None:
            temporary_path.unlink(missing_ok=True)
    return {"text": text}

class DownloadManager:
    """Own all model paths, availability checks, and explicit downloads."""

    def __init__(self, cache_dir: str | Path | None = None):
        root = cache_dir or user_cache_dir("voxlocal")
        self.cache_dir = Path(root).expanduser()
        self.cache_dir.mkdir(parents=True, exist_ok=True)

def download(self, model_id: str) -> Iterator[DownloadProgress]:
    """Download one known model with explicit start and completion records."""
    if self.is_downloaded(model_id):
        yield self._progress(model_id, 100, "already cached")
        return

    yield self._progress(model_id, 0, "download started")
    try:
        if model_id == "supertonic_3":
            self._download_supertonic()
        elif model_id == "whisper_base":
            self._download_whisper()
        elif model_id == "sensevoice_onnx":
            self._download_sensevoice()
        elif model_id == "moonshine_es":
            self._download_moonshine()
        else:
            raise ValueError(f"Unknown model: {model_id}")
    except (DependencyMissingError, ValueError):
        raise
    except Exception as error:
        raise ModelDownloadError(
            f"Failed to download model '{model_id}': {error}"
        ) from error

    if not self.is_downloaded(model_id):
        raise ModelDownloadError(
            f"Download for '{model_id}' completed without all required files"
        )
    yield self._progress(model_id, 100, "download complete")

@staticmethod
def _progress(
    model_id: str, percent: int, description: str
) -> DownloadProgress:
    return DownloadProgress(
        model_id=model_id,
        percent=percent,
        downloaded="complete" if percent == 100 else "pending",
        total="unknown",
        description=f"{model_id}: {description}",
    )

